import React, { createContext, useContext, useState, useEffect } from 'react';
import { authService, AuthResponse, RegisterData, LoginData } from '../services/authService';

interface AuthContextType {
  user: any | null;
  loading: boolean;
  register: (data: RegisterData) => Promise<void>;
  login: (data: LoginData) => Promise<void>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any | null>(null);
  const [loading, setLoading] = useState(true);

  // attempt to load user from token on mount
  useEffect(() => {
    const init = async () => {
      try {
        const res = await authService.getCurrentUser();
        if (res && res.user) setUser(res.user);
      } catch (e) {
        setUser(null);
      } finally {
        setLoading(false);
      }
    };
    init();
  }, []);

  const register = async (data: RegisterData) => {
    const res: AuthResponse = await authService.register(data);
    setUser(res.user);
  };

  const login = async (data: LoginData) => {
    const res: AuthResponse = await authService.login(data);
    setUser(res.user);
  };

  const logout = () => {
    authService.logout();
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, loading, register, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
};
